var weightKg = bodyWeight * 0.4536;
    var r = gender === 'male' ? 0.68 : 0.55;
    var gramsAlcohol = drinks * 14;
    var peakBac = (gramsAlcohol / (weightKg * r * 10)) - (0.015 * hoursSpan * 0.5);
    peakBac = Math.max(0, peakBac);
    var eliminationRate = 0.015;
    var elapsed = Math.max(0, hoursAgo - hoursSpan);
    var currentBac = Math.max(0, peakBac - (eliminationRate * elapsed));
    var timeToZero = currentBac / eliminationRate;
    var timeToLegal = Math.max(0, (currentBac - 0.08) / eliminationRate);
    document.getElementById('peakBAC').textContent = peakBac.toFixed(3) + '%';
    document.getElementById('currentBAC').textContent = currentBac.toFixed(3) + '%';
    document.getElementById('soberTime').textContent = currentBac <= 0 ? 'Already at 0.00%' : fmt(timeToZero, 1) + ' hours from now';
    document.getElementById('legalTime').textContent = currentBac <= 0.08 ? 'Already below 0.08%' : fmt(timeToLegal, 1) + ' hours from now';

var nrr = parseInt(hearingProtection);
    var effective = noiseLevel - (nrr > 0 ? (nrr - 7) * 0.5 : 0);
    var allowable = 8 / Math.pow(2, (effective - 85) / 3);
    var dose = (hoursPerDay / allowable) * 100;
    var lifetimeDose = dose * daysPerWeek * 52 * yearsExposure / 100;
    var risk;
    if (dose <= 50) risk = 'Low risk — within safe limits';
    else if (dose <= 100) risk = 'Moderate risk — near the limit';
    else if (dose <= 200) risk = 'High risk — exceeds safe limits, hearing damage likely over time';
    else risk = 'Very high risk — immediate hearing damage possible';
    document.getElementById('effectiveNoise').textContent = fmt(effective, 0) + ' dB (after protection)';
    document.getElementById('allowableTime').textContent = allowable >= 24 ? 'No time limit (safe)' : fmt(allowable, 1) + ' hours/day max';
    document.getElementById('dosePercent').textContent = fmt(dose, 0) + '% of daily limit';
    document.getElementById('riskLevel').textContent = risk;

var activity = parseFloat(activityLevel);
    var climateFactor = parseFloat(climate);
    var baseOz = bodyWeight * 0.5;
    var adjustedOz = baseOz * activity * climateFactor;
    var caffeineOz = caffeine * 4;
    var totalOz = adjustedOz + caffeineOz;
    var liters = totalOz * 0.02957;
    var glasses = totalOz / 8;
    var hourly = totalOz / 16;
    document.getElementById('dailyOz').textContent = fmt(totalOz, 0) + ' oz';
    document.getElementById('dailyLiters').textContent = fmt(liters, 1) + ' L';
    document.getElementById('glassesPerDay').textContent = fmt(glasses, 1) + ' glasses';
    document.getElementById('hourlyRate').textContent = fmt(hourly, 0) + ' oz/hour';

var skin = parseInt(skinType);
    var exposed = parseInt(skinExposed);
    var baseProdRate = [1000, 800, 600, 400, 250, 150];
    var ratePerMin = baseProdRate[skin - 1] * (uvIndex / 6) * (exposed / 25) / 20;
    var totalIU = ratePerMin * minutes;
    var burnTimes = [10, 15, 20, 30, 50, 70];
    var burnTime = burnTimes[skin - 1] * (6 / uvIndex);
    var optimalMin = Math.min(burnTime * 0.5, 30);
    var rec;
    if (minutes < optimalMin) rec = 'You could safely stay longer. Optimal: ' + fmt(optimalMin, 0) + ' min.';
    else if (minutes < burnTime) rec = 'Good exposure. Apply sunscreen if staying longer.';
    else rec = 'Risk of sunburn! Apply SPF 30+ sunscreen or seek shade.';
    document.getElementById('vitaminD').textContent = fmt(totalIU, 0) + ' IU (target: 600-4000 IU/day)';
    document.getElementById('optimalTime').textContent = fmt(optimalMin, 0) + ' minutes (before sunscreen needed)';
    document.getElementById('burnTime').textContent = fmt(burnTime, 0) + ' minutes at UV ' + uvIndex;
    document.getElementById('recommendation').textContent = rec;

var tnss = sneezing + congestion + runnyNose + itchyEyes + itchyThroat;
    var qol = sleepImpact + activityImpact;
    var total = tnss + qol;
    var maxScore = 21;
    var pct = (total / maxScore) * 100;
    var severity, rec;
    if (total <= 5) { severity = 'Mild'; rec = 'Over-the-counter antihistamine may be sufficient. Try nasal saline rinses.'; }
    else if (total <= 10) { severity = 'Moderate'; rec = 'Consider daily antihistamine + nasal corticosteroid spray. Minimize allergen exposure.'; }
    else if (total <= 15) { severity = 'Moderate-Severe'; rec = 'See an allergist. May benefit from prescription medications or immunotherapy.'; }
    else { severity = 'Severe'; rec = 'Consult an allergist promptly. Immunotherapy (allergy shots/drops) may be recommended.'; }
    var qolText = qol <= 1 ? 'Minimal impact' : qol <= 3 ? 'Moderate impact' : 'Significant impact on daily life';
    document.getElementById('totalScore').textContent = total + ' / ' + maxScore + ' (' + fmt(pct, 0) + '%)';
    document.getElementById('severity').textContent = severity;
    document.getElementById('qualityImpact').textContent = qolText;
    document.getElementById('recommendation').textContent = rec;

var animals = ['Monkey','Rooster','Dog','Pig','Rat','Ox','Tiger','Rabbit','Dragon','Snake','Horse','Goat'];
    var elements = ['Metal','Metal','Water','Water','Wood','Wood','Fire','Fire','Earth','Earth'];
    var traits = {'Rat':'Clever, resourceful, versatile','Ox':'Dependable, strong, determined','Tiger':'Brave, confident, competitive','Rabbit':'Gentle, elegant, alert','Dragon':'Confident, ambitious, energetic','Snake':'Wise, intuitive, graceful','Horse':'Active, energetic, free-spirited','Goat':'Calm, gentle, creative','Monkey':'Witty, intelligent, playful','Rooster':'Observant, hardworking, courageous','Dog':'Loyal, honest, kind','Pig':'Compassionate, generous, diligent'};
    var idx = birthYear % 12;
    var animal = animals[idx];
    var elemIdx = birthYear % 10;
    var element = elements[elemIdx];
    var pIdx = partnerYear % 12;
    var pAnimal = animals[pIdx];
    var bestMatch = {'Rat':'Dragon, Monkey, Ox','Ox':'Rat, Snake, Rooster','Tiger':'Horse, Dog, Pig','Rabbit':'Goat, Dog, Pig','Dragon':'Rat, Monkey, Rooster','Snake':'Ox, Rooster, Monkey','Horse':'Tiger, Goat, Dog','Goat':'Rabbit, Horse, Pig','Monkey':'Rat, Dragon, Snake','Rooster':'Ox, Dragon, Snake','Dog':'Tiger, Rabbit, Horse','Pig':'Tiger, Rabbit, Goat'};
    var best = bestMatch[animal] || '';
    var isMatch = best.indexOf(pAnimal) !== -1;
    document.getElementById('animal').textContent = animal + ' (' + birthYear + ')';
    document.getElementById('element').textContent = element + ' ' + animal;
    document.getElementById('traits').textContent = traits[animal];
    document.getElementById('compatibility').textContent = animal + ' + ' + pAnimal + ': ' + (isMatch ? 'Excellent match!' : 'Challenging — requires understanding') + ' | Best matches for ' + animal + ': ' + best;

var deck = parseInt(deckSize);
    var drawn = parseInt(cardsDrawn);
    var target = Math.min(targetCards, drawn);
    var rev = reversed === 'yes';
    function factorial(n) { if (n <= 1) return 1; var r = 1; for (var i = 2; i <= n; i++) r *= i; return r; }
    function comb(n, k) { if (k > n || k < 0) return 0; if (k === 0 || k === n) return 1; var r = 1; for (var i = 0; i < k; i++) { r *= (n - i); r /= (i + 1); } return r; }
    var totalCombs = comb(deck, drawn);
    var probExact = comb(target, target) * comb(deck - target, drawn - target) / totalCombs;
    var majors = deck === 78 ? 22 : (deck === 22 ? 22 : 0);
    var probAllMajor = majors > 0 ? comb(majors, drawn) / totalCombs : 0;
    var suitSize = deck === 78 ? 14 : (deck === 56 ? 14 : deck);
    var probSameSuit = deck >= 56 ? (4 * comb(suitSize, drawn)) / totalCombs : 1;
    if (rev) { totalCombs = Math.pow(deck * 2, drawn); probExact = Math.pow(1/(deck*2), target); }
    document.getElementById('exactProb').textContent = (probExact * 100).toFixed(4) + '% (1 in ' + fmt(1/probExact, 0) + ')';
    document.getElementById('majorArcanaProb').textContent = majors > 0 ? (probAllMajor * 100).toFixed(2) + '%' : 'N/A for this deck';
    document.getElementById('suitProb').textContent = deck >= 56 ? (probSameSuit * 100).toFixed(2) + '%' : 'N/A';
    document.getElementById('totalCombinations').textContent = totalCombs > 1e15 ? totalCombs.toExponential(2) : fmt(totalCombs, 0);

var net = grossIncome - expenses;
    var seTax = net * (selfEmployTax / 100);
    var seDeduction = seTax * 0.5;
    var taxableIncome = net - seDeduction;
    var incomeTax = taxableIncome * (parseInt(taxBracket) / 100);
    var totalTax = seTax + incomeTax;
    var takeHome = net - totalTax;
    var hourlyRate = hoursPerMonth > 0 ? takeHome / hoursPerMonth : 0;
    document.getElementById('netIncome').textContent = dollar(net) + '/month';
    document.getElementById('totalTax').textContent = dollar(totalTax) + ' (SE: ' + dollar(seTax) + ' + Income: ' + dollar(incomeTax) + ')';
    document.getElementById('takeHome').textContent = dollar(takeHome) + '/month (' + dollar(takeHome * 12) + '/year)';
    document.getElementById('effectiveHourly').textContent = dollar(hourlyRate) + '/hour';

